mapper.select:
SELECT T.USER_ID, T.USER_NM, T.CO_ID, T.DEPT_ID, T.DEPT_NM, T.JBPS_NM, T.STATUS_CD, CASE T.STATUS_CD WHEN 'VAC' THEN '휴가' WHEN 'BIZTRIP' THEN '출장' WHEN 'OUTSIDE' THEN '외근' WHEN 'HOME' THEN '재택' WHEN 'CLIENT' THEN '상주' ELSE '본사' END AS STATUS_NM, CASE WHEN T.STATUS_CD = 'OFFICE' THEN 'N' ELSE 'Y' END AS EXTERNAL_YN, T.SCHDL_NM, T.PROFILE_FILE_SN FROM ( SELECT U.USER_ID, U.USER_NM, U.CO_ID, U.DEPT_ID, D.DEPT_NM, U.JBPS_NM, COALESCE(( SELECT S.SCHDL_SE_CD FROM schdl_info S JOIN schdl_user_rel R ON R.SCHDL_SN = S.SCHDL_SN WHERE R.USER_ID = U.USER_ID AND S.CO_ID = U.CO_ID AND S.USE_YN = 'Y' AND S.SCHDL_SE_CD IN ('VAC', 'BIZTRIP', 'OUTSIDE', 'HOME', 'CLIENT') AND NOW() BETWEEN S.BGNG_DT AND S.END_DT ORDER BY FIELD(S.SCHDL_SE_CD, 'VAC', 'BIZTRIP', 'OUTSIDE', 'HOME', 'CLIENT'), S.BGNG_DT LIMIT 1 ), W.POWK_SE_CD, 'OFFICE') AS STATUS_CD, ( SELECT S.SCHDL_NM FROM schdl_info S JOIN schdl_user_rel R ON R.SCHDL_SN = S.SCHDL_SN WHERE R.USER_ID = U.USER_ID AND S.CO_ID = U.CO_ID AND S.USE_YN = 'Y' AND S.SCHDL_SE_CD IN ('VAC', 'BIZTRIP', 'OUTSIDE', 'HOME', 'CLIENT') AND NOW() BETWEEN S.BGNG_DT AND S.END_DT ORDER BY FIELD(S.SCHDL_SE_CD, 'VAC', 'BIZTRIP', 'OUTSIDE', 'HOME', 'CLIENT'), S.BGNG_DT LIMIT 1 ) AS SCHDL_NM, PF.PROFILE_FILE_SN FROM user_info U LEFT JOIN dept_info D ON D.DEPT_ID = U.DEPT_ID LEFT JOIN work_hstry W ON W.USER_ID = U.USER_ID AND W.WORK_YMD = CURDATE() LEFT JOIN ( SELECT F.REF_ID, MAX(F.ATCH_FILE_SN) AS PROFILE_FILE_SN FROM atch_file_info F WHERE F.CO_ID = #{coId} AND F.REF_SE_CD = 'USER' AND F.FILE_SE_CD = 'PROFILE' AND F.USE_YN = 'Y' GROUP BY F.REF_ID ) PF ON PF.REF_ID = U.USER_ID WHERE U.CO_ID = #{coId} AND U.USE_YN = 'Y'
AND U.DEPT_ID = #{deptId}
) T ORDER BY CASE WHEN T.STATUS_CD = 'OFFICE' THEN 1 ELSE 0 END, T.USER_NM, T.USER_ID

